source:
OPT-NC
{{ .Site.BaseURL }}
{{ now.Format "Mon, 02 Jan 2006 15:04:05 -0700" }}

{{ range $key, $jsonData := .Site.Data.avps }}

    {{ "" | safeHTML }}{{ $jsonData.title | htmlUnescape | safeHTML }}{{ "" | safeHTML }}
    {{ "" | safeHTML }}{{ $jsonData.identifier }}{{ "" | safeHTML }}

    {{ "" | safeHTML }}{{ $.Site.BaseURL }}avps/{{ $key }}/{{ "" | safeHTML }}

    {{ "OPT-NC" | safeHTML }}
    {{ "" | safeHTML }}{{ $jsonData.datePosted }}{{ "" | safeHTML }}

    {{ if $jsonData.validThrough }}
      {{ "" | safeHTML }}{{ $jsonData.validThrough }}{{ "" | safeHTML }}
    {{ end }}

    {{ $city := "Nouméa" }}
    {{ if $jsonData.applicantLocationRequirements }}
      {{ if $jsonData.applicantLocationRequirements.address }}
        {{ $city = $jsonData.applicantLocationRequirements.address.addressLocality }}
      {{ end }}
    {{ else if $jsonData.jobLocation }}
      {{ if $jsonData.jobLocation.address }}
         {{ $city = $jsonData.jobLocation.address.addressLocality }}
      {{ end }}
    {{ end }}
    {{ "" | safeHTML }}{{ $city }}{{ "" | safeHTML }}
    {{ "Nouvelle-Calédonie" | safeHTML }}

    {{/* 🎯 La ligne corrigée est ici (sans le "Rhodes" !!) */}}
    {{ "" | safeHTML }}{{ $jsonData.occupationalCategory | default "Autres métiers" | htmlUnescape | safeHTML }}{{ "" | safeHTML }}

    {{ "" | safeHTML }}
      {{ if $jsonData.description }}
        <p><strong>Description du poste :</strong><br>{{ $jsonData.description | htmlUnescape | safeHTML }}</p>
      {{ end }}

      {{ if $jsonData.responsibilities }}
        <p><strong>Missions principales :</strong></p>
        <ul>
          {{ range $jsonData.responsibilities }}
            <li>{{ . | htmlUnescape | safeHTML }}</li>
          {{ end }}
        </ul>
      {{ end }}

      {{ if $jsonData.skills }}
        <p><strong>Compétences et profil recherché :</strong></p>
        <ul>
          {{ range $jsonData.skills }}
            <li>{{ . | htmlUnescape | safeHTML }}</li>
          {{ end }}
        </ul>
      {{ end }}


    {{ "" | safeHTML }}

{{ end }}
